import{_ as i,o as a,c as l,ag as o}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"형식 검증 (보안 모델)","description":"OpenClaw의 최고 위험 경로에 대한 기계 검증 보안 모델.","frontmatter":{"title":"형식 검증 (보안 모델)","description":"OpenClaw의 최고 위험 경로에 대한 기계 검증 보안 모델."},"headers":[],"relativePath":"security/formal-verification.md","filePath":"security/formal-verification.md","lastUpdated":null}'),t={name:"security/formal-verification.md"};function s(n,e,r,d,c,p){return a(),l("div",null,[...e[0]||(e[0]=[o(`<h1 id="형식-검증-보안-모델" tabindex="-1">형식 검증 (보안 모델) <a class="header-anchor" href="#형식-검증-보안-모델" aria-label="Permalink to &quot;형식 검증 (보안 모델)&quot;">​</a></h1><p>이 페이지는 OpenClaw의 <strong>형식 보안 모델</strong> (오늘은 TLA+/TLC; 필요에 따라 더 추가)을 추적합니다.</p><blockquote><p>참고: 일부 오래된 링크는 이전 프로젝트 이름을 참조할 수 있습니다.</p></blockquote><p><strong>목표 (북극성):</strong> OpenClaw가 명시적 가정 하에 의도된 보안 정책(인증, 세션 격리, 도구 게이팅, 잘못된 구성 안전성)을 시행한다는 기계 검증된 논증을 제공합니다.</p><p><strong>현재 상태:</strong> 실행 가능한, 공격자 주도의 <strong>보안 회귀 스위트</strong>:</p><ul><li>각 주장은 유한 상태 공간에 대해 실행 가능한 모델 검사가 있습니다.</li><li>많은 주장에는 현실적인 버그 클래스에 대한 반례 추적을 생성하는 <strong>음성 모델</strong>이 쌍으로 있습니다.</li></ul><p><strong>아직 아닌 것:</strong> &quot;OpenClaw가 모든 면에서 안전하다&quot; 또는 전체 TypeScript 구현이 올바르다는 증명.</p><h2 id="모델이-있는-위치" tabindex="-1">모델이 있는 위치 <a class="header-anchor" href="#모델이-있는-위치" aria-label="Permalink to &quot;모델이 있는 위치&quot;">​</a></h2><p>모델은 별도의 리포지토리에 유지됩니다: <a href="https://github.com/vignesh07/openclaw-formal-models" target="_blank" rel="noreferrer">vignesh07/openclaw-formal-models</a>.</p><h2 id="중요한-주의-사항" tabindex="-1">중요한 주의 사항 <a class="header-anchor" href="#중요한-주의-사항" aria-label="Permalink to &quot;중요한 주의 사항&quot;">​</a></h2><ul><li>이것은 <strong>모델</strong>이지 전체 TypeScript 구현이 아닙니다. 모델과 코드 간의 드리프트가 가능합니다.</li><li>결과는 TLC가 탐색하는 상태 공간에 의해 제한됩니다. &quot;녹색&quot;이 모델화된 가정과 경계를 넘어서는 보안을 의미하지 않습니다.</li><li>일부 주장은 명시적 환경 가정(예: 올바른 배포, 올바른 구성 입력)에 의존합니다.</li></ul><h2 id="결과-재현" tabindex="-1">결과 재현 <a class="header-anchor" href="#결과-재현" aria-label="Permalink to &quot;결과 재현&quot;">​</a></h2><p>현재 결과는 모델 리포지토리를 로컬로 복제하고 TLC를 실행하여 재현됩니다 (아래 참조). 향후 반복에서는 다음을 제공할 수 있습니다:</p><ul><li>공개 아티팩트가 있는 CI 실행 모델 (반례 추적, 실행 로그)</li><li>소규모 제한 검사를 위한 호스팅된 &quot;이 모델 실행&quot; 워크플로</li></ul><p>시작하기:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/vignesh07/openclaw-formal-models</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw-formal-models</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Java 11+ 필요 (TLC는 JVM에서 실행됨).</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 리포지토리는 고정된 \`tla2tools.jar\` (TLA+ 도구)를 제공하고 \`bin/tlc\` + Make 대상을 제공합니다.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h3 id="게이트웨이-노출-및-열린-게이트웨이-잘못-구성" tabindex="-1">게이트웨이 노출 및 열린 게이트웨이 잘못 구성 <a class="header-anchor" href="#게이트웨이-노출-및-열린-게이트웨이-잘못-구성" aria-label="Permalink to &quot;게이트웨이 노출 및 열린 게이트웨이 잘못 구성&quot;">​</a></h3><p><strong>주장:</strong> 인증 없이 루프백을 초과하는 바인딩은 원격 손상을 가능하게 하거나 노출을 증가시킬 수 있습니다. 토큰/비밀번호는 미인증 공격자를 차단합니다 (모델 가정에 따름).</p><ul><li>녹색 실행: <ul><li><code>make gateway-exposure-v2</code></li><li><code>make gateway-exposure-v2-protected</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make gateway-exposure-v2-negative</code></li></ul></li></ul><p>모델 리포지토리의 <code>docs/gateway-exposure-matrix.md</code>도 참조하십시오.</p><h3 id="노드-exec-파이프라인-최고-위험-기능" tabindex="-1">노드 exec 파이프라인 (최고 위험 기능) <a class="header-anchor" href="#노드-exec-파이프라인-최고-위험-기능" aria-label="Permalink to &quot;노드 exec 파이프라인 (최고 위험 기능)&quot;">​</a></h3><p><strong>주장:</strong> <code>exec host=node</code>는 (a) 노드 명령 허용 목록 및 선언된 명령과 (b) 구성된 경우 라이브 승인이 필요합니다. 승인은 재생을 방지하기 위해 토큰화됩니다 (모델에서).</p><ul><li>녹색 실행: <ul><li><code>make nodes-pipeline</code></li><li><code>make approvals-token</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make nodes-pipeline-negative</code></li><li><code>make approvals-token-negative</code></li></ul></li></ul><h3 id="페어링-저장소-dm-게이팅" tabindex="-1">페어링 저장소 (DM 게이팅) <a class="header-anchor" href="#페어링-저장소-dm-게이팅" aria-label="Permalink to &quot;페어링 저장소 (DM 게이팅)&quot;">​</a></h3><p><strong>주장:</strong> 페어링 요청은 TTL과 대기 요청 한도를 준수합니다.</p><ul><li>녹색 실행: <ul><li><code>make pairing</code></li><li><code>make pairing-cap</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make pairing-negative</code></li><li><code>make pairing-cap-negative</code></li></ul></li></ul><h3 id="인그레스-게이팅-멘션-제어-명령-우회" tabindex="-1">인그레스 게이팅 (멘션 + 제어 명령 우회) <a class="header-anchor" href="#인그레스-게이팅-멘션-제어-명령-우회" aria-label="Permalink to &quot;인그레스 게이팅 (멘션 + 제어 명령 우회)&quot;">​</a></h3><p><strong>주장:</strong> 멘션이 필요한 그룹 컨텍스트에서 미승인 &quot;제어 명령&quot;은 멘션 게이팅을 우회할 수 없습니다.</p><ul><li>녹색: <ul><li><code>make ingress-gating</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make ingress-gating-negative</code></li></ul></li></ul><h3 id="라우팅-세션-키-격리" tabindex="-1">라우팅/세션 키 격리 <a class="header-anchor" href="#라우팅-세션-키-격리" aria-label="Permalink to &quot;라우팅/세션 키 격리&quot;">​</a></h3><p><strong>주장:</strong> 서로 다른 피어의 DM은 명시적으로 연결/구성되지 않는 한 동일한 세션으로 합쳐지지 않습니다.</p><ul><li>녹색: <ul><li><code>make routing-isolation</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make routing-isolation-negative</code></li></ul></li></ul><h2 id="v1-추가-제한-모델-동시성-재시도-추적-정확성" tabindex="-1">v1++: 추가 제한 모델 (동시성, 재시도, 추적 정확성) <a class="header-anchor" href="#v1-추가-제한-모델-동시성-재시도-추적-정확성" aria-label="Permalink to &quot;v1++: 추가 제한 모델 (동시성, 재시도, 추적 정확성)&quot;">​</a></h2><p>이것은 실제 실패 모드 (비원자적 업데이트, 재시도, 메시지 팬아웃) 주변의 신뢰성을 강화하는 후속 모델입니다.</p><h3 id="페어링-저장소-동시성-멱등성" tabindex="-1">페어링 저장소 동시성 / 멱등성 <a class="header-anchor" href="#페어링-저장소-동시성-멱등성" aria-label="Permalink to &quot;페어링 저장소 동시성 / 멱등성&quot;">​</a></h3><p><strong>주장:</strong> 페어링 저장소는 인터리빙 하에서도 <code>MaxPending</code>과 멱등성을 시행해야 합니다 (즉, &quot;확인-후-쓰기&quot;는 원자적/잠금 상태여야 합니다; 새로 고침은 중복을 생성하지 않아야 합니다).</p><ul><li>녹색 실행: <ul><li><code>make pairing-race</code> (원자적/잠금 한도 확인)</li><li><code>make pairing-idempotency</code></li><li><code>make pairing-refresh</code></li><li><code>make pairing-refresh-race</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make pairing-race-negative</code> (비원자적 begin/commit 한도 경쟁)</li><li><code>make pairing-idempotency-negative</code></li><li><code>make pairing-refresh-negative</code></li><li><code>make pairing-refresh-race-negative</code></li></ul></li></ul><h3 id="인그레스-추적-상관관계-멱등성" tabindex="-1">인그레스 추적 상관관계 / 멱등성 <a class="header-anchor" href="#인그레스-추적-상관관계-멱등성" aria-label="Permalink to &quot;인그레스 추적 상관관계 / 멱등성&quot;">​</a></h3><p><strong>주장:</strong> 수집은 팬아웃 전체에서 추적 상관관계를 보존하고 프로바이더 재시도 하에서 멱등적이어야 합니다.</p><ul><li>녹색: <ul><li><code>make ingress-trace</code></li><li><code>make ingress-trace2</code></li><li><code>make ingress-idempotency</code></li><li><code>make ingress-dedupe-fallback</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make ingress-trace-negative</code></li><li><code>make ingress-trace2-negative</code></li><li><code>make ingress-idempotency-negative</code></li><li><code>make ingress-dedupe-fallback-negative</code></li></ul></li></ul><h3 id="라우팅-dmscope-우선-순위-identitylinks" tabindex="-1">라우팅 dmScope 우선 순위 + identityLinks <a class="header-anchor" href="#라우팅-dmscope-우선-순위-identitylinks" aria-label="Permalink to &quot;라우팅 dmScope 우선 순위 + identityLinks&quot;">​</a></h3><p><strong>주장:</strong> 라우팅은 기본적으로 DM 세션을 격리하고 명시적으로 구성된 경우에만 세션을 합칩니다 (채널 우선 순위 + 아이덴티티 링크).</p><ul><li>녹색: <ul><li><code>make routing-precedence</code></li><li><code>make routing-identitylinks</code></li></ul></li><li>빨간색 (예상): <ul><li><code>make routing-precedence-negative</code></li><li><code>make routing-identitylinks-negative</code></li></ul></li></ul>`,43)])])}const g=i(t,[["render",s]]);export{u as __pageData,g as default};
